def parse_minutes(text):
    parts = text.split(",")
    minutes = []

    for part in parts:
        minutes.append(int(part.strip()))

    return minutes


def total_minutes(minutes_list):
    return sum(minutes_list)


def average_minutes(minutes_list):
    return sum(minutes_list) / len(minutes_list)


def build_report(title, minutes_text):
    minutes_list = parse_minutes(minutes_text)
    total = total_minutes(minutes_list)
    average = average_minutes(minutes_list)
    return f"{title} | total: {total} | average: {average}"
